#include <bits/stdc++.h>
using namespace std;
const int N=150005;
struct node
{
    long long num,id;
    bool operator<(const node other) const
    {
        return num<other.num;
    }
} a[N];
long long n,q,pos[N],s[N],ans;
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        a[i].id=i;
        cin>>a[i].num;
    }
    sort(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        pos[a[i].id]=i;
        ans+=(a[i].num*i);
        s[i]=s[i-1]+a[i].num;
    }
    cin>>q;
    while(q--)
    {
        long long x,y;
        cin>>x>>y;
        int poss=pos[x];
        auto it=lower_bound(a+1,a+1+n,node{y,0});
        int pos_after=it-a;
        if(pos_after<=poss)
        {
            long long ans2=ans-(a[poss].num*poss)+s[poss-1]-s[pos_after-1]+y*pos_after;
            cout<<ans2<<"\n";
        }
        else
        {
            int l=poss,r=pos_after-1;
            long long ans2=ans-(a[l].num*l)-(s[r]-s[l])+(y*r);
            cout<<ans2<<"\n";
        }
    }
    return 0;
}
